class Solution:
    def minArraySum(self, nums):
        max_v = max(nums)
        present = [False] * (max_v + 1)
        for v in set(nums):
            present[v] = True
        best = [0] * (max_v + 1)
        for v in range(1, max_v + 1):
            if present[v]:
                for m in range(v, max_v + 1, v):
                    if best[m] == 0:
                        best[m] = v
        return sum(best[x] for x in nums)

