var minArraySum = function(nums) {
    const maxV = Math.max(...nums);
    const present = new Array(maxV + 1).fill(false);
    for (const v of nums) present[v] = true;
    const best = new Array(maxV + 1).fill(0);
    for (let v = 1; v <= maxV; v++) {
        if (present[v]) {
            for (let m = v; m <= maxV; m += v) {
                if (best[m] === 0) best[m] = v;
            }
        }
    }
    let total = 0;
    for (const x of nums) total += best[x];
    return total;
};
